import{_ as e,o as a,c as h,e as r}from"./app.50ad9e00.js";const d={},i=r('<h1 id="memo-使用" tabindex="-1"><a class="header-anchor" href="#memo-使用" aria-hidden="true">#</a> Memo 使用</h1><h2 id="基础使用" tabindex="-1"><a class="header-anchor" href="#基础使用" aria-hidden="true">#</a> 基础使用</h2><h3 id="删除" tabindex="-1"><a class="header-anchor" href="#删除" aria-hidden="true">#</a> 删除</h3><p>在Memo的列表中直接左滑，会出现删除的按钮。</p><p>或者通过编辑列表时，进行删除。</p><h3 id="编辑" tabindex="-1"><a class="header-anchor" href="#编辑" aria-hidden="true">#</a> 编辑</h3><p>在Memo详情页中，点击编辑按钮，可以修改Memo标题、内容以及对应的列表归属。</p><h2 id="扩展动作" tabindex="-1"><a class="header-anchor" href="#扩展动作" aria-hidden="true">#</a> 扩展动作</h2><h3 id="复制" tabindex="-1"><a class="header-anchor" href="#复制" aria-hidden="true">#</a> 复制</h3><p>将内容复制到剪切板。</p><p>复制完成后会震动手机，快速确认完成复制。</p><h3 id="分词" tabindex="-1"><a class="header-anchor" href="#分词" aria-hidden="true">#</a> 分词</h3><p>将内容进行分词，展示出分词结果。</p><p>只要点击分词结果，会自动拼接并复制到剪切板。</p><h3 id="跳转" tabindex="-1"><a class="header-anchor" href="#跳转" aria-hidden="true">#</a> 跳转</h3><p>如果内容为网址或者邮箱，点击后会自动跳转到浏览器或者邮件应用打开。</p><h3 id="分享" tabindex="-1"><a class="header-anchor" href="#分享" aria-hidden="true">#</a> 分享</h3><p>分享按钮在右上角。</p><p>点击后触发系统的内容分享页面，可以自己选择分享的应用或者出发快捷动作。</p>',19),n=[i];function t(c,o){return a(),h("div",null,n)}const p=e(d,[["render",t],["__file","memo.html.vue"]]);export{p as default};
